import{St as e,j as t,k as n}from"./C2wy_3lr.js";import"./CT0T0Gak.js";import"./cry5Dbjr.js";var r={title:`Presenting the DREAMER Project at Oracle Academy Webinar “OA Days in Ukraine”`,date:`26.02.2026`,categories:[`events`],published:!0},{title:i,date:a,categories:o,published:s}=r,c=t(`<p>DREAMER was featured at the Oracle Academy webinar “OA Days in Ukraine,” where Associate Professor Oleksii Yehorchenkov of Comenius University in Bratislava, Slovakia, delivered a presentation on how the DREAMER project aims to contribute to the post-war recovery of Ukraine. According to the event programme, his session took place at 2:45 PM as part of the official Oracle Academy in Ukraine agenda.</p> <p>The webinar brought together speakers from Oracle Ukraine, academia, and partner initiatives to discuss educational opportunities, digital skills, and international cooperation. Within this context, the DREAMER presentation highlighted the project’s relevance for strengthening project management capacity and supporting future reconstruction efforts in Ukraine.</p>`,1);function l(t){var r=c();e(2),n(t,r)}export{l as default,r as metadata};